import{_ as b,o as a,c as e,j as A,a as t,a1 as B}from"./chunks/framework.Bp7r_-XI.js";const p="data:image/jpeg;base64,",i=JSON.parse('{"title":"11.万能系","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/人格面具/攻击系/11.万能系.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/人格面具/攻击系/11.万能系.md"}'),E={name:"4.资源分区/6.技艺及称号/通用及综合类/人格面具/攻击系/11.万能系.md"};function Q(o,r,s,l,d,n){return a(),e("div",null,[...r[0]||(r[0]=[A("h1",{id:"_11-万能系",tabindex:"-1"},[t("11.万能系 "),A("a",{class:"header-anchor",href:"#_11-万能系","aria-label":'Permalink to "11.万能系"'},"​")],-1),A("table",{class:"bannerparthead"},[A("tbody",null,[A("tr",{id:"hdr"},[A("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),B('<h1 id="万能系" tabindex="-1">万能系：<img src="'+p+'" alt=""> <a class="header-anchor" href="#万能系" aria-label="Permalink to &quot;万能系：![](./万能.jpg)&quot;">​</a></h1><p>万能系：<br> 与其它攻击系技能不同，本技能系大部分是照成无属性或全属性的混合伤害，只有全吸收、全伤害类型无效、无敌等具有通用性质的防御能抵挡。但是以上情况仅在面对人格体系是如此的，在面对其余体系的视为全伤害类型取劣的伤害类型。</p><p>【吸血】<br> 等级：B<br> 习得提供能力值：8<br> 消耗SP：3<br> 动作：标准<br> 射程：1米×【决心】+1米×【魔÷4】<br> 范围：单体<br> 持续：立即<br> 对抗：无<br> 效果：不进行检定，直接造成数值为【大量】的无属性伤害，不可豁免，并且为召唤者恢复等量伤势，医疗点为12点×【魔÷5】。<br> 遗忘提供能力值：16</p><p>【吸魔】<br> 等级：B<br> 习得提供能力值：8<br> 消耗SP：3<br> 动作：标准<br> 射程：1米×【决心】+1米×【魔÷4】<br> 范围：单体<br> 持续：立即<br> 对抗：防御<br> 效果：造成【大量】无属性伤害，但是不造成伤害，而是将伤害转为等量的能量消耗，由目标自由决定消耗那种能量池，并且能为召唤者恢复等量SP，不受能量池恢复上限限制。<br> 遗忘提供能力值：16</p><p>【米吉多】<br> 等级：C<br> 习得提供能力值：4<br> 消耗SP：3<br> 动作：标准<br> 射程：1米×【决心】+1米×【魔÷2】<br> 范围：射程内所有敌方目标<br> 持续：立即<br> 对抗：反射<br> 效果：造成【中量】万能属性的混合伤害。<br> 遗忘提供能力值：8</p><p>【米吉多拉】<br> 等级：B<br> 习得提供能力值：8<br> 消耗SP：5<br> 动作：标准<br> 射程：5米×【决心】+4米×【魔】<br> 范围：射程内所有敌方目标<br> 持续：立即<br> 对抗：反射<br> 效果：造成【大量】万能属性的混合伤害。<br> 遗忘提供能力值：16</p><p>【米吉多拉翁】<br> 等级：A<br> 习得提供能力值：16<br> 消耗SP：7<br> 动作：标准<br> 射程：100米×【决心】+40米×【魔】<br> 范围：射程内所有敌方目标<br> 持续：立即<br> 对抗：反射<br> 效果：造成【特大量】万能属性的混合伤害。<br> 遗忘提供能力值：32</p><p>【污秽吐息】<br> 等级：B<br> 习得提供能力值：8<br> 消耗SP：5<br> 动作：标准<br> 射程：1米×【决心】+1米×【魔】<br> 范围：个体<br> 持续：【战斗结束/15分钟】取低<br> 对抗：无<br> 效果：使目标更容易陷入异常状态，目标的豁免检定承受20点运气减值，这种减值只会影响目标在受到任何有概率触发效果的技能时，技能施放者获得仅针对目标进行攻击时的20点运气加值，这种状态会持续【战斗结束/15分钟】取低。<br> 遗忘提供能力值：16</p><p>【污秽空气】<br> 前置：污秽吐息<br> 等级：B<br> 习得提供能力值：26<br> 消耗SP：5<br> 动作：标准<br> 射程：2米×【决心】+2米×【魔】<br> 范围：以自身为起点，半径等于射程的圆形<br> 持续：【战斗结束/15分钟】取低<br> 对抗：无<br> 效果：使技能技能范围变成空气浑浊的的地形，在地形包括召唤者在内的所有目标更容易陷入异常状态，受影响单位在豁免检定上都会承受40点运气减值，这种减值只会影响目标在受到任何有概率触发效果的技能时，技能释放者获得仅针对目标进行攻击时的40点运气加值，地形会持续【战斗结束/15分钟】取低。<br> 遗忘提供能力值：16</p><p>【亡者喟叹】<br> 等级：B<br> 习得提供能力值：8<br> 消耗SP：5<br> 动作：标准<br> 射程：5米×【决心】+3米×【魔】<br> 范围：射程内所有敌方目标<br> 持续：立即<br> 对抗：强韧<br> 效果：不造成伤害，而是在目标陷入【恐惧】的时候触发【即死】效果，强韧豁免对抗本效果。<br> 遗忘提供能力值：16</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const g=b(E,[["render",Q]]);export{i as __pageData,g as default};
